package dsl

import (
	"context"
	"os"
	"testing"

	"github.com/xraph/warden"
	"github.com/xraph/warden/store/memory"
)

// large.warden is generated by testdata/bench/gen.go.
// It contains roughly: 200 permissions, 100 roles (with parent chains
// every 5), 20 resource types with relations + expressions, 30 policies.
func loadLargeBench(b *testing.B) []byte {
	b.Helper()
	src, err := os.ReadFile("testdata/bench/large.warden")
	if err != nil {
		b.Fatalf("missing testdata/bench/large.warden — generate via `go run gen.go` in that dir: %v", err)
	}
	return src
}

func BenchmarkLex(b *testing.B) {
	src := loadLargeBench(b)
	b.SetBytes(int64(len(src)))
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		l := NewLexer("large.warden", src)
		for {
			t := l.Next()
			if t.Kind == EOF {
				break
			}
		}
	}
}

func BenchmarkParse(b *testing.B) {
	src := loadLargeBench(b)
	b.SetBytes(int64(len(src)))
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		_, _ = Parse("large.warden", src)
	}
}

func BenchmarkResolve(b *testing.B) {
	src := loadLargeBench(b)
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		prog, _ := Parse("large.warden", src)
		_ = Resolve(prog)
	}
}

func BenchmarkApplyMemory(b *testing.B) {
	src := loadLargeBench(b)
	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		b.StopTimer()
		s := memory.New()
		eng, _ := warden.NewEngine(warden.WithStore(s))
		prog, _ := Parse("large.warden", src)
		b.StartTimer()
		if _, err := Apply(context.Background(), eng, prog, ApplyOptions{}); err != nil {
			b.Fatal(err)
		}
	}
}

// BenchmarkApplyIdempotent measures the cost of a no-op re-apply against an
// already-populated store. This is the steady-state cost of GitOps reconcile.
func BenchmarkApplyIdempotent(b *testing.B) {
	src := loadLargeBench(b)
	prog0, _ := Parse("large.warden", src)
	s := memory.New()
	eng, _ := warden.NewEngine(warden.WithStore(s))
	if _, err := Apply(context.Background(), eng, prog0, ApplyOptions{}); err != nil {
		b.Fatal(err)
	}

	b.ReportAllocs()
	b.ResetTimer()
	for i := 0; i < b.N; i++ {
		prog, _ := Parse("large.warden", src)
		if _, err := Apply(context.Background(), eng, prog, ApplyOptions{}); err != nil {
			b.Fatal(err)
		}
	}
}
